**Why This Is Dangerous**:
- Outdated go-getter (pre-1.7.4) allows arbitrary file writes via path traversal
- Git URL parameters can inject malicious git config options
- Decompressed archives can contain symlinks pointing outside destination
- No validation of source URLs allows attackers to specify internal resources

**SECURE VERSION**:

```go
package main

import (
	"context"
	"fmt"
	"net/url"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"time"

	getter "github.com/hashicorp/go-getter/v2" // v2.2.1+ with security fixes
)

var (
	allowedSchemes  = map[string]bool{"https": true, "s3": true}
	allowedDomains  = []string{"artifacts.company.com", "s3.amazonaws.com"}
	domainValidator = regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9.-]*[a-zA-Z0-9]$`)
)

func validateSourceURL(sourceURL string) error {
	parsed, err := url.Parse(sourceURL)
	if err != nil {
		return fmt.Errorf("invalid URL format: %w", err)
	}

	// Validate scheme
	if !allowedSchemes[strings.ToLower(parsed.Scheme)] {
		return fmt.Errorf("scheme %q not allowed, use https or s3", parsed.Scheme)
	}

	// Validate hostname format
	if !domainValidator.MatchString(parsed.Hostname()) {
		return fmt.Errorf("invalid hostname format")
	}

	// Check against allowlist
	allowed := false
	for _, domain := range allowedDomains {
		if strings.HasSuffix(parsed.Hostname(), domain) {
			allowed = true
			break
		}
	}
	if !allowed {
		return fmt.Errorf("domain %q not in allowlist", parsed.Hostname())
	}

	// Block dangerous URL parameters
	blockParams := []string{"sshkey", "config", "depth", "ref"}
	for _, param := range blockParams {
		if parsed.Query().Has(param) {
			return fmt.Errorf("URL parameter %q not allowed", param)
		}
	}

	return nil
}

func downloadArtifactSecure(ctx context.Context, sourceURL string, destPath string) error {
	// Validate source URL
	if err := validateSourceURL(sourceURL); err != nil {
		return fmt.Errorf("URL validation failed: %w", err)
	}

	// Ensure destination is within allowed directory
	absDest, err := filepath.Abs(destPath)
	if err != nil {
		return fmt.Errorf("invalid destination path: %w", err)
	}

	allowedBase := "/var/artifacts"
	if !strings.HasPrefix(absDest, allowedBase) {
		return fmt.Errorf("destination must be within %s", allowedBase)
	}

	// Use secure getter configuration
	req := &getter.Request{
		Src: sourceURL,
		Dst: absDest,
		// Disable potentially dangerous getters
		Getters: []getter.Getter{
			new(getter.HttpGetter),
			// Note: Git getter disabled due to security concerns
		},
	}

	// Set timeout
	ctx, cancel := context.WithTimeout(ctx, 5*time.Minute)
	defer cancel()

	client := getter.DefaultClient
	_, err = client.Get(ctx, req)
	if err != nil {
		return fmt.Errorf("download failed: %w", err)
	}

	return nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: app <source_url> <dest_path>")
		os.Exit(1)
	}

	ctx := context.Background()
	if err := downloadArtifactSecure(ctx, os.Args[1], os.Args[2]); err != nil {
		fmt.Fprintf(os.Stderr, "Error: %v\n", err)
		os.Exit(1)
	}
}
```

**Key Security Controls**:
- **Updated dependency**: Uses go-getter v2.2.1+ with security patches for CVE-2024-3817 and CVE-2024-6257
- **URL allowlisting**: Only permits downloads from known trusted domains via HTTPS/S3
- **Parameter blocking**: Prevents dangerous URL parameters like sshkey and config
- **Path validation**: Ensures destination is within allowed directory to prevent traversal
- **Disabled Git getter**: Removes the most vulnerable protocol handler

For CI/CD pipelines, you need a comprehensive dependency security strategy that includes Software Bill of Materials (SBOM), vulnerability scanning, and secure fetching patterns.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"io"
	"net/http"
	"net/url"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"sync"
	"time"

	"github.com/hashicorp/go-retryablehttp"
	"go.uber.org/zap"
)

// ArtifactManifest defines expected artifacts with integrity checks
type ArtifactManifest struct {
	Version   string     `json:"version"`
	Artifacts []Artifact `json:"artifacts"`
}

type Artifact struct {
	Name         string `json:"name"`
	Source       string `json:"source"`
	SHA256       string `json:"sha256"`
	AllowedFrom  string `json:"allowed_from"` // Domain pattern
	MaxSizeBytes int64  `json:"max_size_bytes"`
}

type SecureArtifactFetcher struct {
	logger         *zap.Logger
	httpClient     *retryablehttp.Client
	allowedDomains map[string]*regexp.Regexp
	tempDir        string
	downloadDir    string
	maxConcurrent  int
	semaphore      chan struct{}
}

func NewSecureArtifactFetcher(logger *zap.Logger, config FetcherConfig) (*SecureArtifactFetcher, error) {
	// Initialize HTTP client with security settings
	httpClient := retryablehttp.NewClient()
	httpClient.RetryMax = 3
	httpClient.RetryWaitMin = 1 * time.Second
	httpClient.RetryWaitMax = 10 * time.Second
	httpClient.HTTPClient.Timeout = 10 * time.Minute

	// Disable redirects to external domains
	httpClient.HTTPClient.CheckRedirect = func(req *http.Request, via []*http.Request) error {
		if len(via) >= 3 {
			return fmt.Errorf("too many redirects")
		}
		return nil
	}

	// Compile allowed domain patterns
	allowedDomains := make(map[string]*regexp.Regexp)
	for name, pattern := range config.AllowedDomains {
		re, err := regexp.Compile(pattern)
		if err != nil {
			return nil, fmt.Errorf("invalid domain pattern %s: %w", name, err)
		}
		allowedDomains[name] = re
	}

	return &SecureArtifactFetcher{
		logger:         logger,
		httpClient:     httpClient,
		allowedDomains: allowedDomains,
		tempDir:        config.TempDir,
		downloadDir:    config.DownloadDir,
		maxConcurrent:  config.MaxConcurrent,
		semaphore:      make(chan struct{}, config.MaxConcurrent),
	}, nil
}

type FetcherConfig struct {
	AllowedDomains map[string]string
	TempDir        string
	DownloadDir    string
	MaxConcurrent  int
}

func (f *SecureArtifactFetcher) ValidateArtifact(artifact Artifact) error {
	// Parse and validate URL
	parsedURL, err := url.Parse(artifact.Source)
	if err != nil {
		return fmt.Errorf("invalid source URL: %w", err)
	}

	// Enforce HTTPS only
	if parsedURL.Scheme != "https" {
		return fmt.Errorf("only HTTPS sources allowed, got: %s", parsedURL.Scheme)
	}

	// Validate against allowed domain patterns
	matched := false
	for name, pattern := range f.allowedDomains {
		if pattern.MatchString(parsedURL.Host) {
			f.logger.Debug("domain matched pattern",
				zap.String("host", parsedURL.Host),
				zap.String("pattern", name))
			matched = true
			break
		}
	}
	if !matched {
		return fmt.Errorf("source domain %s not in allowlist", parsedURL.Host)
	}

	// Validate SHA256 format
	if len(artifact.SHA256) != 64 {
		return fmt.Errorf("invalid SHA256 hash length")
	}
	if _, err := hex.DecodeString(artifact.SHA256); err != nil {
		return fmt.Errorf("invalid SHA256 hash format: %w", err)
	}

	return nil
}

func (f *SecureArtifactFetcher) FetchWithIntegrity(ctx context.Context, artifact Artifact) error {
	// Acquire semaphore for concurrency control
	select {
	case f.semaphore <- struct{}{}:
		defer func() { <-f.semaphore }()
	case <-ctx.Done():
		return ctx.Err()
	}

	// Validate artifact configuration
	if err := f.ValidateArtifact(artifact); err != nil {
		f.logger.Error("artifact validation failed",
			zap.String("artifact", artifact.Name),
			zap.Error(err))
		return err
	}

	// Create temp file for download
	tempFile, err := os.CreateTemp(f.tempDir, "artifact-*.tmp")
	if err != nil {
		return fmt.Errorf("failed to create temp file: %w", err)
	}
	tempPath := tempFile.Name()
	defer os.Remove(tempPath) // Clean up temp file

	// Create HTTP request with context
	req, err := retryablehttp.NewRequestWithContext(ctx, "GET", artifact.Source, nil)
	if err != nil {
		tempFile.Close()
		return fmt.Errorf("failed to create request: %w", err)
	}

	// Add security headers
	req.Header.Set("User-Agent", "SecureArtifactFetcher/1.0")
	req.Header.Set("Accept", "application/octet-stream")

	f.logger.Info("starting download",
		zap.String("artifact", artifact.Name),
		zap.String("source", artifact.Source))

	// Execute request
	resp, err := f.httpClient.Do(req)
	if err != nil {
		tempFile.Close()
		return fmt.Errorf("download failed: %w", err)
	}
	defer resp.Body.Close()

	if resp.StatusCode != http.StatusOK {
		tempFile.Close()
		return fmt.Errorf("unexpected status code: %d", resp.StatusCode)
	}

	// Limit download size
	limitedReader := io.LimitReader(resp.Body, artifact.MaxSizeBytes)

	// Calculate hash while downloading
	hasher := sha256.New()
	multiWriter := io.MultiWriter(tempFile, hasher)

	written, err := io.Copy(multiWriter, limitedReader)
	tempFile.Close()

	if err != nil {
		return fmt.Errorf("download write failed: %w", err)
	}

	// Verify integrity
	actualHash := hex.EncodeToString(hasher.Sum(nil))
	if !strings.EqualFold(actualHash, artifact.SHA256) {
		f.logger.Error("integrity check failed",
			zap.String("artifact", artifact.Name),
			zap.String("expected", artifact.SHA256),
			zap.String("actual", actualHash))
		return fmt.Errorf("SHA256 mismatch: expected %s, got %s", artifact.SHA256, actualHash)
	}

	// Move to final destination
	finalPath := filepath.Join(f.downloadDir, filepath.Base(artifact.Name))
	if err := os.Rename(tempPath, finalPath); err != nil {
		// Fall back to copy if rename fails (cross-device)
		if err := copyFile(tempPath, finalPath); err != nil {
			return fmt.Errorf("failed to move artifact: %w", err)
		}
	}

	f.logger.Info("artifact downloaded successfully",
		zap.String("artifact", artifact.Name),
		zap.Int64("size_bytes", written),
		zap.String("sha256", actualHash))

	return nil
}

func (f *SecureArtifactFetcher) FetchManifest(ctx context.Context, manifest ArtifactManifest) error {
	var wg sync.WaitGroup
	errChan := make(chan error, len(manifest.Artifacts))

	for _, artifact := range manifest.Artifacts {
		wg.Add(1)
		go func(art Artifact) {
			defer wg.Done()
			if err := f.FetchWithIntegrity(ctx, art); err != nil {
				errChan <- fmt.Errorf("artifact %s: %w", art.Name, err)
			}
		}(artifact)
	}

	wg.Wait()
	close(errChan)

	// Collect errors
	var errs []error
	for err := range errChan {
		errs = append(errs, err)
	}

	if len(errs) > 0 {
		return fmt.Errorf("%d artifacts failed: %v", len(errs), errs)
	}

	return nil
}

func copyFile(src, dst string) error {
	source, err := os.Open(src)
	if err != nil {
		return err
	}
	defer source.Close()

	dest, err := os.Create(dst)
	if err != nil {
		return err
	}
	defer dest.Close()

	_, err = io.Copy(dest, source)
	return err
}

func main() {
	// Initialize structured logger
	logger, _ := zap.NewProduction()
	defer logger.Sync()

	// Load manifest from signed/verified source
	manifestData, err := os.ReadFile("artifacts.json")
	if err != nil {
		logger.Fatal("failed to read manifest", zap.Error(err))
	}

	var manifest ArtifactManifest
	if err := json.Unmarshal(manifestData, &manifest); err != nil {
		logger.Fatal("failed to parse manifest", zap.Error(err))
	}

	// Configure fetcher with security settings
	config := FetcherConfig{
		AllowedDomains: map[string]string{
			"github_releases": `^github\.com$`,
			"company_s3":      `^[a-z0-9-]+\.s3\.amazonaws\.com$`,
			"company_artifacts": `^artifacts\.company\.com$`,
		},
		TempDir:       "/tmp/artifacts",
		DownloadDir:   "/opt/app/dependencies",
		MaxConcurrent: 4,
	}

	fetcher, err := NewSecureArtifactFetcher(logger, config)
	if err != nil {
		logger.Fatal("failed to create fetcher", zap.Error(err))
	}

	ctx, cancel := context.WithTimeout(context.Background(), 30*time.Minute)
	defer cancel()

	if err := fetcher.FetchManifest(ctx, manifest); err != nil {
		logger.Fatal("manifest fetch failed", zap.Error(err))
	}

	logger.Info("all artifacts downloaded successfully")
}
```

