*/

require 'vendor/autoload.php';

use PHPMailer\PHPMailer\PHPMailer;
use PHPMailer\PHPMailer\Exception;

class SecureContactController {
    private PHPMailer $mail;
    private array $allowedDomains = ['gmail.com', 'yahoo.com', 'outlook.com'];

    public function __construct() {
        $this->mail = new PHPMailer(true);
        $this->mail->isSMTP();
        $this->mail->Host = getenv('SMTP_HOST');
        $this->mail->SMTPAuth = true;
        $this->mail->Username = getenv('SMTP_USER');
        $this->mail->Password = getenv('SMTP_PASS');
        $this->mail->SMTPSecure = PHPMailer::ENCRYPTION_STARTTLS;
        $this->mail->Port = 587;
    }

    public function sendEmail(array $request): array {
        // Validate email format strictly
        $email = filter_var($request['email'] ?? '', FILTER_VALIDATE_EMAIL);
        if (!$email) {
            throw new InvalidArgumentException('Invalid email format');
        }

        // Validate email domain
        $domain = explode('@', $email)[1] ?? '';
        if (!in_array($domain, $this->allowedDomains, true)) {
            error_log("Blocked email from unauthorized domain: {$domain}");
            throw new InvalidArgumentException('Email domain not allowed');
        }

        // Sanitize name (alphanumeric, spaces, basic punctuation only)
        $name = preg_replace('/[^a-zA-Z0-9\s\-\.]/', '', $request['name'] ?? 'Anonymous');
        $name = substr($name, 0, 100);

        try {
            $this->mail->setFrom('noreply@company.com', 'Contact Form');
            $this->mail->addReplyTo($email, $name);
            $this->mail->addAddress('admin@company.com');
            $this->mail->Subject = htmlspecialchars(substr($request['subject'] ?? '', 0, 200));
            $this->mail->Body = htmlspecialchars($request['message'] ?? '');
            $this->mail->send();

            return ['status' => 'sent'];
        } catch (Exception $e) {
            error_log("Mail error: " . $e->getMessage());
            throw new RuntimeException('Failed to send email');
        }
    }
}
```

**Key Security Controls**:
- **Pinned versions**: Exact version constraints prevent automatic vulnerable updates
- **roave/security-advisories**: Blocks installation of packages with known vulnerabilities
- **Input validation**: Email format and domain validation prevents injection attacks
- **Sanitization**: All user input is sanitized before use in mail functions
- **Environment variables**: Sensitive credentials stored outside codebase

Setting up automated dependency scanning requires multiple layers of security checks integrated into your development workflow. After the Log4Shell incident and similar supply chain attacks, organizations must treat dependency security as a continuous process, not a one-time audit.

**PRODUCTION PATTERN**:

```php
<?php
// src/Security/DependencyAuditor.php
namespace App\Security;

use Psr\Log\LoggerInterface;
use Symfony\Component\Process\Process;
use Symfony\Component\Process\Exception\ProcessFailedException;

class DependencyAuditor {
    private LoggerInterface $logger;
    private string $projectRoot;
    private array $config;

    public function __construct(
        LoggerInterface $logger,
        string $projectRoot,
        array $config = []
    ) {
        $this->logger = $logger;
        $this->projectRoot = $projectRoot;
        $this->config = array_merge([
            'severity_threshold' => 'high',
            'fail_on_vulnerability' => true,
            'slack_webhook' => getenv('SLACK_SECURITY_WEBHOOK'),
            'allowed_licenses' => ['MIT', 'Apache-2.0', 'BSD-3-Clause', 'ISC'],
        ], $config);
    }

    public function runFullAudit(): array {
        $results = [
            'timestamp' => date('c'),
            'composer_audit' => $this->runComposerAudit(),
            'license_check' => $this->checkLicenses(),
            'outdated_check' => $this->checkOutdated(),
            'lockfile_integrity' => $this->verifyLockfile(),
        ];

        $this->logResults($results);
        $this->alertIfCritical($results);

        return $results;
    }

    private function runComposerAudit(): array {
        $process = new Process(
            ['composer', 'audit', '--format=json', '--no-interaction'],
            $this->projectRoot
        );
        $process->setTimeout(120);
        $process->run();

        $output = json_decode($process->getOutput(), true) ?? [];

        $vulnerabilities = [];
        foreach ($output['advisories'] ?? [] as $package => $advisories) {
            foreach ($advisories as $advisory) {
                $vulnerabilities[] = [
                    'package' => $package,
                    'cve' => $advisory['cve'] ?? 'N/A',
                    'title' => $advisory['title'] ?? 'Unknown',
                    'severity' => $this->mapSeverity($advisory['severity'] ?? 'unknown'),
                    'affected_versions' => $advisory['affectedVersions'] ?? 'unknown',
                    'patched_version' => $advisory['sources'][0]['remediatedVersions'] ?? 'N/A',
                    'link' => $advisory['link'] ?? '',
                ];
            }
        }

        return [
            'status' => empty($vulnerabilities) ? 'pass' : 'fail',
            'count' => count($vulnerabilities),
            'vulnerabilities' => $vulnerabilities,
        ];
    }

    private function checkLicenses(): array {
        $process = new Process(
            ['composer', 'licenses', '--format=json'],
            $this->projectRoot
        );
        $process->run();

        $licenses = json_decode($process->getOutput(), true)['dependencies'] ?? [];
        $violations = [];

        foreach ($licenses as $package => $info) {
            $packageLicenses = (array)($info['license'] ?? []);
            $allowed = false;

            foreach ($packageLicenses as $license) {
                if (in_array($license, $this->config['allowed_licenses'], true)) {
                    $allowed = true;
                    break;
                }
            }

            if (!$allowed) {
                $violations[] = [
                    'package' => $package,
                    'license' => implode(', ', $packageLicenses),
                ];
            }
        }

        return [
            'status' => empty($violations) ? 'pass' : 'warning',
            'violations' => $violations,
        ];
    }

    private function checkOutdated(): array {
        $process = new Process(
            ['composer', 'outdated', '--direct', '--format=json'],
            $this->projectRoot
        );
        $process->run();

        $outdated = json_decode($process->getOutput(), true)['installed'] ?? [];

        $critical = array_filter($outdated, function($pkg) {
            return isset($pkg['latest']) && 
                   version_compare($pkg['version'], $pkg['latest'], '<') &&
                   $this->isMajorVersionBehind($pkg['version'], $pkg['latest']);
        });

        return [
            'status' => empty($critical) ? 'pass' : 'warning',
            'total_outdated' => count($outdated),
            'critical_outdated' => count($critical),
            'packages' => array_slice($outdated, 0, 20),
        ];
    }

    private function verifyLockfile(): array {
        $lockfile = $this->projectRoot . '/composer.lock';

        if (!file_exists($lockfile)) {
            return ['status' => 'fail', 'error' => 'composer.lock not found'];
        }

        $process = new Process(
            ['composer', 'validate', '--no-check-all', '--no-check-publish'],
            $this->projectRoot
        );
        $process->run();

        $lockContent = json_decode(file_get_contents($lockfile), true);
        $contentHash = $lockContent['content-hash'] ?? null;

        return [
            'status' => $process->isSuccessful() ? 'pass' : 'fail',
            'content_hash' => $contentHash,
            'package_count' => count($lockContent['packages'] ?? []),
        ];
    }

    private function mapSeverity(string $severity): string {
        $map = [
            'critical' => 'CRITICAL',
            'high' => 'HIGH', 
            'medium' => 'MEDIUM',
            'low' => 'LOW',
        ];
        return $map[strtolower($severity)] ?? 'UNKNOWN';
    }

    private function isMajorVersionBehind(string $current, string $latest): bool {
        $currentMajor = (int)explode('.', ltrim($current, 'v'))[0];
        $latestMajor = (int)explode('.', ltrim($latest, 'v'))[0];
        return $latestMajor > $currentMajor;
    }

    private function logResults(array $results): void {
        $this->logger->info('Dependency audit completed', [
            'vulnerabilities_found' => $results['composer_audit']['count'] ?? 0,
            'license_violations' => count($results['license_check']['violations'] ?? []),
            'outdated_packages' => $results['outdated_check']['total_outdated'] ?? 0,
        ]);
    }

    private function alertIfCritical(array $results): void {
        $criticalVulns = array_filter(
            $results['composer_audit']['vulnerabilities'] ?? [],
            fn($v) => $v['severity'] === 'CRITICAL'
        );

        if (!empty($criticalVulns) && $this->config['slack_webhook']) {
            $this->sendSlackAlert($criticalVulns);
        }
    }

    private function sendSlackAlert(array $vulnerabilities): void {
        $message = "🚨 *Critical Security Vulnerabilities Detected*\n\n";
        foreach ($vulnerabilities as $vuln) {
            $message .= "• *{$vuln['package']}*: {$vuln['title']}\n";
            $message .= "  CVE: {$vuln['cve']} | Fix: {$vuln['patched_version']}\n";
        }

        $payload = json_encode(['text' => $message]);

        $ch = curl_init($this->config['slack_webhook']);
        curl_setopt_array($ch, [
            CURLOPT_POST => true,
            CURLOPT_POSTFIELDS => $payload,
            CURLOPT_HTTPHEADER => ['Content-Type: application/json'],
            CURLOPT_RETURNTRANSFER => true,
            CURLOPT_TIMEOUT => 10,
        ]);
        curl_exec($ch);
        curl_close($ch);
    }
}
