```javascript
// secure-install.js - Verified dependency installation
const { execSync } = require('child_process');
const fs = require('fs');
const crypto = require('crypto');

function verifyLockfile() {
  if (!fs.existsSync('package-lock.json')) {
    throw new Error('package-lock.json required for secure installs');
  }

  // Verify lockfile hasn't been tampered with
  const lockContent = fs.readFileSync('package-lock.json', 'utf8');
  const hash = crypto.createHash('sha256').update(lockContent).digest('hex');
  console.log(`Lockfile SHA256: ${hash}`);

  return true;
}

function secureInstall() {
  try {
    verifyLockfile();

    // Use --ignore-scripts to prevent postinstall attacks
    // Use --audit to check for vulnerabilities
    console.log('Installing with security checks...');
    execSync('npm ci --ignore-scripts', { stdio: 'inherit' });

    // Run audit after installation
    console.log('Running security audit...');
    const auditResult = execSync('npm audit --json', { encoding: 'utf8' });
    const audit = JSON.parse(auditResult);

    if (audit.metadata.vulnerabilities.critical > 0) {
      throw new Error(`Critical vulnerabilities found: ${audit.metadata.vulnerabilities.critical}`);
    }

    console.log('Secure installation complete');
  } catch (error) {
    console.error('Security check failed:', error.message);
    process.exit(1);
  }
}

secureInstall();
```

**Key Security Controls**:
- **Exact version pinning**: Prevents automatic upgrades to malicious versions
- **npm ci instead of npm install**: Uses package-lock.json exactly, fails if inconsistent
- **--ignore-scripts flag**: Blocks postinstall script execution (review manually)
- **npm audit integration**: Catches known vulnerabilities before deployment

