```javascript
// scripts/dependency-monitor.js - Automated vulnerability monitoring
const https = require('https');
const fs = require('fs');
const { execSync } = require('child_process');

class DependencyMonitor {
  constructor(config) {
    this.slackWebhook = config.slackWebhook;
    this.severityThreshold = config.severityThreshold || 'high';
    this.packageLockPath = config.packageLockPath || 'package-lock.json';
  }

  async runFullAudit() {
    const results = {
      timestamp: new Date().toISOString(),
      npmAudit: null,
      outdatedPackages: null,
      licenseIssues: null,
      riskScore: 0
    };

    try {
      // NPM audit for known vulnerabilities
      results.npmAudit = this.runNpmAudit();

      // Check for outdated packages
      results.outdatedPackages = this.checkOutdated();

      // License compliance check
      results.licenseIssues = this.checkLicenses();

      // Calculate risk score
      results.riskScore = this.calculateRiskScore(results);

      // Alert if threshold exceeded
      if (results.riskScore >= 7) {
        await this.sendAlert(results);
      }

      // Store results for trending
      this.storeResults(results);

      return results;
    } catch (error) {
      console.error('Audit failed:', error.message);
      await this.sendAlert({ error: error.message, severity: 'critical' });
      throw error;
    }
  }

  runNpmAudit() {
    try {
      const output = execSync('npm audit --json 2>/dev/null', {
        encoding: 'utf8',
        maxBuffer: 10 * 1024 * 1024
      });
      return JSON.parse(output);
    } catch (error) {
      // npm audit exits non-zero when vulnerabilities found
      if (error.stdout) {
        return JSON.parse(error.stdout);
      }
      throw error;
    }
  }

  checkOutdated() {
    try {
      const output = execSync('npm outdated --json 2>/dev/null || true', {
        encoding: 'utf8'
      });
      return output ? JSON.parse(output) : {};
    } catch (error) {
      return {};
    }
  }

  checkLicenses() {
    const problematicLicenses = ['GPL-3.0', 'AGPL-3.0', 'SSPL-1.0'];
    const issues = [];

    try {
      const output = execSync('npx license-checker --json', {
        encoding: 'utf8'
      });
      const licenses = JSON.parse(output);

      for (const [pkg, info] of Object.entries(licenses)) {
        if (problematicLicenses.some(l => info.licenses?.includes(l))) {
          issues.push({ package: pkg, license: info.licenses });
        }
      }
    } catch (error) {
      console.warn('License check failed:', error.message);
    }

    return issues;
  }

  calculateRiskScore(results) {
    let score = 0;
    const vulns = results.npmAudit?.metadata?.vulnerabilities || {};

    score += (vulns.critical || 0) * 4;
    score += (vulns.high || 0) * 2;
    score += (vulns.moderate || 0) * 1;
    score += results.licenseIssues?.length * 0.5 || 0;

    // Check for severely outdated packages (> 2 major versions behind)
    const outdated = results.outdatedPackages || {};
    for (const [pkg, info] of Object.entries(outdated)) {
      if (info.current && info.latest) {
        const currentMajor = parseInt(info.current.split('.')[0]);
        const latestMajor = parseInt(info.latest.split('.')[0]);
        if (latestMajor - currentMajor >= 2) {
          score += 1;
        }
      }
    }

    return Math.min(score, 10);
  }

  async sendAlert(results) {
    const message = {
      text: `:warning: Dependency Security Alert`,
      blocks: [
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: `*Risk Score: ${results.riskScore}/10*\n` +
              `Critical: ${results.npmAudit?.metadata?.vulnerabilities?.critical || 0}\n` +
              `High: ${results.npmAudit?.metadata?.vulnerabilities?.high || 0}`
          }
        }
      ]
    };

    if (this.slackWebhook) {
      await this.postToSlack(message);
    }

    console.log('Alert sent:', JSON.stringify(message, null, 2));
  }

  postToSlack(message) {
    return new Promise((resolve, reject) => {
      const url = new URL(this.slackWebhook);
      const req = https.request({
        hostname: url.hostname,
        path: url.pathname,
        method: 'POST',
        headers: { 'Content-Type': 'application/json' }
      }, (res) => {
        res.statusCode === 200 ? resolve() : reject(new Error(`Slack: ${res.statusCode}`));
      });
      req.write(JSON.stringify(message));
      req.end();
    });
  }

  storeResults(results) {
    const auditLog = 'audit-history.jsonl';
    fs.appendFileSync(auditLog, JSON.stringify(results) + '\n');
  }
}

// Usage
const monitor = new DependencyMonitor({
  slackWebhook: process.env.SLACK_SECURITY_WEBHOOK,
  severityThreshold: 'high'
});

monitor.runFullAudit()
  .then(results => {
    console.log(`Audit complete. Risk score: ${results.riskScore}/10`);
    process.exit(results.riskScore >= 7 ? 1 : 0);
  })
  .catch(error => {
    console.error('Fatal:', error);
    process.exit(1);
  });
