Automating dependency security is essential for production systems. The 2023 3CX supply chain attack demonstrated how compromised dependencies can infiltrate build pipelines, affecting 600,000+ organizations. Here's a comprehensive approach for Go applications.

**PRODUCTION PATTERN**:

```go
package security

import (
	"context"
	"encoding/json"
	"fmt"
	"log"
	"os"
	"os/exec"
	"strings"
	"time"
)

// VulnerabilityReport represents govulncheck output
type VulnerabilityReport struct {
	Vulnerabilities []Vulnerability `json:"vulns"`
	ScannedAt       time.Time       `json:"scanned_at"`
	GoVersion       string          `json:"go_version"`
}

type Vulnerability struct {
	ID          string   `json:"id"`
	Aliases     []string `json:"aliases"` // CVE numbers
	Severity    string   `json:"severity"`
	Package     string   `json:"package"`
	Version     string   `json:"version"`
	FixedIn     string   `json:"fixed_in"`
	Description string   `json:"description"`
}

type DependencyScanner struct {
	allowedVulnIDs map[string]bool // Explicitly accepted vulnerabilities
	maxSeverity    string
	logger         *log.Logger
}

func NewDependencyScanner(maxSeverity string) *DependencyScanner {
	return &DependencyScanner{
		allowedVulnIDs: make(map[string]bool),
		maxSeverity:    maxSeverity,
		logger:         log.New(os.Stdout, "[SECURITY] ", log.LstdFlags),
	}
}

// ScanDependencies runs govulncheck and returns vulnerabilities
func (ds *DependencyScanner) ScanDependencies(ctx context.Context, projectPath string) (*VulnerabilityReport, error) {
	ds.logger.Printf("Starting vulnerability scan for: %s", projectPath)

	// Run govulncheck (Go's official vulnerability scanner)
	cmd := exec.CommandContext(ctx, "govulncheck", "-json", "./...")
	cmd.Dir = projectPath

	output, err := cmd.Output()
	if err != nil {
		// govulncheck returns non-zero if vulnerabilities found
		if exitErr, ok := err.(*exec.ExitError); ok {
			ds.logger.Printf("Vulnerabilities detected (exit code: %d)", exitErr.ExitCode())
		} else {
			return nil, fmt.Errorf("govulncheck execution failed: %w", err)
		}
	}

	report := &VulnerabilityReport{
		ScannedAt: time.Now().UTC(),
	}

	// Parse govulncheck JSON output
	if err := json.Unmarshal(output, report); err != nil {
		return nil, fmt.Errorf("failed to parse scan results: %w", err)
	}

	ds.logger.Printf("Scan complete: %d vulnerabilities found", len(report.Vulnerabilities))
	return report, nil
}

// ValidateForProduction checks if vulnerabilities block deployment
func (ds *DependencyScanner) ValidateForProduction(report *VulnerabilityReport) error {
	var criticalVulns []Vulnerability
	var highVulns []Vulnerability

	for _, vuln := range report.Vulnerabilities {
		// Skip explicitly allowed vulnerabilities (with documentation)
		if ds.allowedVulnIDs[vuln.ID] {
			ds.logger.Printf("ALLOWED: %s (explicitly accepted)", vuln.ID)
			continue
		}

		switch strings.ToUpper(vuln.Severity) {
		case "CRITICAL":
			criticalVulns = append(criticalVulns, vuln)
		case "HIGH":
			highVulns = append(highVulns, vuln)
		}
	}

	// Always block on CRITICAL vulnerabilities
	if len(criticalVulns) > 0 {
		for _, v := range criticalVulns {
			ds.logger.Printf("CRITICAL: %s in %s@%s - Fix: %s", v.ID, v.Package, v.Version, v.FixedIn)
		}
		return fmt.Errorf("deployment blocked: %d critical vulnerabilities found", len(criticalVulns))
	}

	// Block on HIGH if policy requires
	if ds.maxSeverity == "HIGH" && len(highVulns) > 0 {
		for _, v := range highVulns {
			ds.logger.Printf("HIGH: %s in %s@%s - Fix: %s", v.ID, v.Package, v.Version, v.FixedIn)
		}
		return fmt.Errorf("deployment blocked: %d high severity vulnerabilities found", len(highVulns))
	}

	ds.logger.Println("Vulnerability scan passed - safe for deployment")
	return nil
}

// GenerateSBOM creates Software Bill of Materials
func (ds *DependencyScanner) GenerateSBOM(ctx context.Context, projectPath string) ([]byte, error) {
	ds.logger.Printf("Generating SBOM for: %s", projectPath)

	// Use cyclonedx-gomod for SBOM generation
	cmd := exec.CommandContext(ctx, "cyclonedx-gomod", "mod", "-json", "-output", "-")
	cmd.Dir = projectPath

	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("SBOM generation failed: %w", err)
	}

	ds.logger.Println("SBOM generated successfully")
	return output, nil
}
```

